+uint16_t TmclRos2::checkApTypeMax()
+{
+  uint16_t max_ap_type_val = 0;
+  for (int bit_count = 0; bit_width_ > bit_count; bit_count++)
+  {
+    max_ap_type_val |= 0x1 << bit_count; 
+  }
+  
+  return max_ap_type_val;
