+
+void TmclRos2::motorValParser(uint8_t * type, uint8_t * motor, uint16_t req_instruct_type)
+{
+  *motor |= (((req_instruct_type < 4096) ? ((0xFF00 & req_instruct_type) >> 4) : \
+    ((0xFF00 & req_instruct_type) >> 8)));
+  *type |= (0x00FF & req_instruct_type);
